WITH row_rank_1 AS (
    SELECT rr.EMPLOYEE_PK, rr.EMP_CD, rr.LOAD_DATE, rr.RECORD_SOURCE,
           ROW_NUMBER() OVER(
               PARTITION BY rr.EMPLOYEE_PK
               ORDER BY rr.LOAD_DATE
           ) AS row_number
    FROM S45969_DBT_DB.S45969_DBT_AH_SCHEMA.v_stg_employee AS rr
    WHERE rr.EMPLOYEE_PK IS NOT NULL
    QUALIFY row_number = 1
),

records_to_insert AS (
    SELECT a.EMPLOYEE_PK, a.EMP_CD, a.LOAD_DATE, a.RECORD_SOURCE
    FROM row_rank_1 AS a
    LEFT JOIN S45969_DBT_DB.S45969_DBT_AH_SCHEMA.hub_employee AS d
    ON a.EMPLOYEE_PK = d.EMPLOYEE_PK
    WHERE d.EMPLOYEE_PK IS NULL
)

SELECT * FROM records_to_insert